+  //   --> add X, (mul nuw (udiv X, C1), (C2 - C1))
+  {
+    const APInt *C1, *C2;
+    Value *UDiv, *X;
+    auto MatchDivRem = [&](Value *Op0, Value *Op1, APInt &K) -> bool {
+      if (match(Op0, m_Shl(m_Value(UDiv), m_APInt(C2)))) {
+        if (!match(UDiv, m_UDiv(m_Value(X), m_APInt(C1))))
+          return false;
+        if (!match(Op1, m_URem(m_Specific(X), m_SpecificInt(*C1))))
+          return false;
+        K = APInt(C2->getBitWidth(), 1) << *C2;
+        return K.ugt(*C1);
+      }
+      if (match(Op0, m_Mul(m_Value(UDiv), m_APInt(C2)))) {
+        if (!match(UDiv, m_UDiv(m_Value(X), m_APInt(C1))))
+          return false;
