+        K = *C2;
+        return K.ugt(*C1);
+      }
+      return false;
+    };
+    APInt K;
+    if (match(&I, m_DisjointOr(m_Value(), m_Value())) &&
+        (MatchDivRem(I.getOperand(0), I.getOperand(1), K) ||
+         MatchDivRem(I.getOperand(1), I.getOperand(0), K))) {
+      Value *Mul = Builder.CreateMul(UDiv, ConstantInt::get(Ty, K - *C1),
+                                     "", /* HasNUW */ true);
+      return BinaryOperator::CreateAdd(Mul, X);
+    }
+  }
